sql_examples.sql:
-- PDB에 접속
ALTER SESSION SET CONTAINER = pdb1;

-- 로컬 사용자 생성
CREATE USER app_user IDENTIFIED BY SecurePass123
  DEFAULT TABLESPACE users
  TEMPORARY TABLESPACE temp
  QUOTA 100M ON users
  PROFILE default;

-- 기본 권한 부여
GRANT CREATE SESSION TO app_user;
GRANT CREATE TABLE, CREATE VIEW, CREATE SEQUENCE TO app_user;

-- CDB 루트에 접속
ALTER SESSION SET CONTAINER = CDB$ROOT;

-- 공통 사용자 생성 (C## 접두사 필수)
CREATE USER C##DBA_ADMIN IDENTIFIED BY AdminPass456
  DEFAULT TABLESPACE users
  TEMPORARY TABLESPACE temp
  CONTAINER = ALL;

-- 모든 컨테이너에 권한 부여
GRANT CREATE SESSION TO C##DBA_ADMIN CONTAINER = ALL;
GRANT DBA TO C##DBA_ADMIN CONTAINER = ALL;

-- 패스워드 변경
ALTER USER app_user IDENTIFIED BY NewSecurePass789;

-- 계정 잠금
ALTER USER app_user ACCOUNT LOCK;

-- 계정 잠금 해제
ALTER USER app_user ACCOUNT UNLOCK;

-- 패스워드 즉시 만료 (다음 접속 시 변경 강제)
ALTER USER app_user PASSWORD EXPIRE;

-- 기본 테이블스페이스 변경
ALTER USER app_user DEFAULT TABLESPACE data_ts;

-- 쿼터(QUOTA) 변경
ALTER USER app_user QUOTA UNLIMITED ON data_ts;
ALTER USER app_user QUOTA 0 ON users;  -- 기존 테이블스페이스 쿼터 제거

-- 프로파일 변경
ALTER USER app_user PROFILE secure_profile;

-- OS 인증 사용자 생성 (IDENTIFIED EXTERNALLY)
CREATE USER OPS$oracle IDENTIFIED EXTERNALLY;
GRANT CREATE SESSION TO OPS$oracle;

-- OS_AUTHENT_PREFIX 확인
SHOW PARAMETER OS_AUTHENT_PREFIX;

-- REMOTE_OS_AUTHENT 확인 (반드시 FALSE여야 함)
SHOW PARAMETER REMOTE_OS_AUTHENT;

-- 외부 인증 사용자 조회
SELECT USERNAME, AUTHENTICATION_TYPE, ACCOUNT_STATUS
FROM DBA_USERS
WHERE AUTHENTICATION_TYPE = 'EXTERNAL';

-- 패스워드 파일에 등록된 사용자 조회
SELECT USERNAME, SYSDBA, SYSOPER, SYSBACKUP, SYSDG, SYSKM, SYSRAC, CON_ID
FROM V$PWFILE_USERS;

-- 사용자에게 SYSDBA 권한 부여 (패스워드 파일에 자동 등록)
GRANT SYSDBA TO C##ADMIN_USER;

-- REMOTE_LOGIN_PASSWORDFILE 파라미터 확인
SHOW PARAMETER REMOTE_LOGIN_PASSWORDFILE;

-- 사용자 삭제 (소유 객체 없는 경우)
DROP USER temp_user;

-- 사용자 및 소유 객체 모두 삭제 (CASCADE)
DROP USER app_user CASCADE;

-- 삭제 전 사용자의 세션 확인
SELECT SID, SERIAL#, USERNAME, STATUS
FROM V$SESSION
WHERE USERNAME = 'APP_USER';

-- 활성 세션 강제 종료 후 삭제
ALTER SYSTEM KILL SESSION 'sid,serial#' IMMEDIATE;

-- 현재 컨테이너 확인
SHOW CON_NAME;
SHOW CON_ID;

-- CDB 루트에서 공통 사용자 생성
ALTER SESSION SET CONTAINER = CDB$ROOT;
CREATE USER C##MONITOR IDENTIFIED BY MonitorPass123
  CONTAINER = ALL;
GRANT CREATE SESSION TO C##MONITOR CONTAINER = ALL;
GRANT SELECT_CATALOG_ROLE TO C##MONITOR CONTAINER = ALL;

-- PDB로 전환하여 로컬 사용자 생성
ALTER SESSION SET CONTAINER = pdb1;
CREATE USER local_app IDENTIFIED BY AppPass123
  DEFAULT TABLESPACE users
  QUOTA 500M ON users;
GRANT CREATE SESSION, CREATE TABLE TO local_app;

-- CDB 전체 사용자 현황 조회 (CDB 루트에서)
ALTER SESSION SET CONTAINER = CDB$ROOT;
SELECT c.NAME AS CONTAINER_NAME, u.USERNAME, u.COMMON, u.ACCOUNT_STATUS
FROM CDB_USERS u
JOIN V$CONTAINERS c ON u.CON_ID = c.CON_ID
WHERE u.ORACLE_MAINTAINED = 'N'
ORDER BY c.NAME, u.USERNAME;
